\`\`\`rust
use rusqlite::{Connection, params};

pub struct TelemetryStorage {
    conn: Connection,
    retention_days: u32,
    aggregate_after_hours: u32,
}

impl TelemetryStorage {
    pub fn new(db_path: &Path) -> Result<Self> {
        let conn = Connection::open(db_path)?;
        conn.execute_batch("PRAGMA journal_mode=WAL; PRAGMA synchronous=NORMAL;")?;
        Self::run_migrations(&conn)?;
        Ok(Self { conn, retention_days: 30, aggregate_after_hours: 24 })
    }

    pub fn insert_telemetry(&self, snapshot: &TelemetrySnapshot) -> Result<()> {
        self.conn.execute(
            "INSERT INTO telemetry_snapshots (worker_id, timestamp, cpu_percent, ...) 
             VALUES (?1, ?2, ?3, ...)",
            params![snapshot.worker_id, snapshot.timestamp.timestamp(), snapshot.cpu.utilization_pct, ...],
        )?;
        Ok(())
    }

    pub fn get_telemetry_range(
        &self, 
        worker_id: &str, 
        start: DateTime<Utc>, 
        end: DateTime<Utc>,
        resolution: Resolution,
    ) -> Result<Vec<TelemetrySnapshot>> {
        match resolution {
            Resolution::Raw => self.get_raw_telemetry(worker_id, start, end),
            Resolution::Hourly => self.get_hourly_telemetry(worker_id, start, end),
        }
    }

    pub fn insert_speedscore(&self, worker_id: &str, score: &SpeedScore) -> Result<()> {
        let tx = self.conn.transaction()?;

        // Insert history record
        tx.execute(
            "INSERT INTO speedscore_history (worker_id, measured_at, total_score, ...) 
             VALUES (?1, ?2, ?3, ...)",
            params![worker_id, score.measured_at.timestamp(), score.total, ...],
        )?;
        let id = tx.last_insert_rowid();

        // Update latest
        tx.execute(
            "INSERT OR REPLACE INTO speedscore_latest (worker_id, speedscore_id, total_score, measured_at)
             VALUES (?1, ?2, ?3, ?4)",
            params![worker_id, id, score.total, score.measured_at.timestamp()],
        )?;

        tx.commit()?;
        Ok(())
    }

    pub fn get_latest_speedscore(&self, worker_id: &str) -> Result<Option<SpeedScore>> {
        // Fast path: query latest table
        let mut stmt = self.conn.prepare_cached(
            "SELECT h.* FROM speedscore_latest l 
             JOIN speedscore_history h ON l.speedscore_id = h.id 
             WHERE l.worker_id = ?1"
        )?;
        // ...
    }
}
